package com.codelens.web;import com.codelens.entity.*;import com.codelens.repo.*;import com.codelens.service.*;import com.fasterxml.jackson.databind.*;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import java.time.Instant;
@RestController @RequiredArgsConstructor public class GitHubWebhookController{private final WebhookSecurity security;private final ObjectMapper mapper;private final RepositoryRepo repos;private final PullRequestRepo prs;private final PullRequestProcessor processor;@PostMapping("/webhook/github") public ResponseEntity<String> webhook(@RequestBody String body,@RequestHeader(value="X-Hub-Signature-256",required=false)String sig,@RequestHeader(value="X-GitHub-Event",required=false)String event)throws Exception{if(!security.valid(body,sig))return ResponseEntity.status(401).body("bad signature"); if(!"pull_request".equals(event))return ResponseEntity.ok("ignored");JsonNode root=mapper.readTree(body);JsonNode p=root.path("pull_request");JsonNode r=root.path("repository");String full=r.path("full_name").asText();RepositoryEntity repo=repos.findByFullName(full).orElseGet(()->repos.save(new RepositoryEntity(full,r.path("html_url").asText())));PullRequestEntity pr=prs.findByRepositoryFullNameAndNumber(full,p.path("number").asInt()).orElseGet(PullRequestEntity::new);pr.setRepository(repo);pr.setNumber(p.path("number").asInt());pr.setTitle(p.path("title").asText());pr.setAuthor(p.path("user").path("login").asText());pr.setDiffUrl(p.path("diff_url").asText());pr.setHtmlUrl(p.path("html_url").asText());pr.setState(p.path("state").asText());pr.setStatus("RECEIVED");pr.setUpdatedAt(Instant.now());pr=prs.save(pr);processor.process(pr.getId(),p.path("head").path("sha").asText());return ResponseEntity.ok("accepted");}}
